//React
import {React, Component, useState} from 'react';
import * as FaIcons from "react-icons/fa";



function PainelDeControle(){
    const [eventosSelecionado, setEventosSelecionado] = useState(false);
    const [clientesSelecionado, setClientesSelecionado] = useState(false);
    const [brinquedosSelecionado, setBrinquedosSelecionado] = useState(false);
    

    function handleClickOpcao(opcaoClicada){        
        switch(opcaoClicada){
            case 'evento':  eventosSelecionado? setEventosSelecionado(false) : setEventosSelecionado(true);
            break;
            case 'clientes': clientesSelecionado? setClientesSelecionado(false) : setClientesSelecionado(true);
            break;
            case 'clientes': brinquedosSelecionado? setBrinquedosSelecionado(false) : setBrinquedosSelecionado(true);
        }
    }
        
    return(
        <div id='PainelDeControle'>
            <div className='seletores'>
                <div id='opcoes' className='configOpcoes'>
                    
                    <div className='opcao linkFake' onClick={() => handleClickOpcao('eventos')}>
                        <div>
                            <FaIcons.FaBirthdayCake size = {40} />
                        </div>
                        <div> 
                            <p>
                                EVENTOS
                            </p>
                        </div>
                    </div>

                    <div className={`opcao linkFake ${eventosSelecionado? 'clicado':''}`} onClick={() => handleClickOpcao('clientes')}>
                        <div>
                            <FaIcons.FaUserCircle size = {40}/>
                        </div>
                        <div> 
                            <p>
                                CLIENTES
                            </p>
                        </div>
                    </div>

                    <div className='opcao linkFake' onClick={() => handleClickOpcao('brinquedos')}>
                        <div>
                            <FaIcons.FaSnowman size = {40}/>
                        </div>
                        <div> 
                            <p>
                                BRINQUEDOS
                            </p>
                        </div>
                    </div>
                </div>
            </div>  
        </div>            
    )    
    
}

export default PainelDeControle;
